diff --git a/src/__tests__/json.test.ts b/src/__tests__/json.test.ts
index 6ac6eb1..72c51a4 100644
--- a/src/__tests__/json.test.ts
+++ b/src/__tests__/json.test.ts
@@ -17,6 +17,7 @@ import {
 import { buildExecutionContext } from "graphql/execution/execute";
 import { compileQuery } from "../index";
 import { queryToJSONSchema } from "../json";
+import { makeExecutableSchema } from "@graphql-tools/schema";

 describe("json schema creator", () => {
   const BlogAuthor = new GraphQLObjectType({
@@ -168,3 +169,54 @@ describe("json schema creator", () => {
     });
   });
 });
+
+describe("JSON schema creation with abstract types", () => {
+  let inf: any;
+  const schema = makeExecutableSchema({
+    typeDefs: `
+        type Query {
+          foo: Foo
+          u: U
+        }
+        union U = Foo | Bar
+
+        type Foo {
+          a: String
+          b: Int
+          c: Boolean!
+          d: Bar
+        }
+        type Bar {
+          e: String!
+          f: Boolean!
+        }
+      `,
+    resolvers: {
+      Query: {
+        foo(_: any, _1: any, _2: any, info: any) {
+          inf = info;
+        },
+        u(_: any, _1: any, _2: any, info: any) {
+          inf = info;
+        }
+      }
+    }
+  });
+  const document = parse(/* GraphQL */ `
+    {
+      u
+    }
+  `);
+  const context: any =
+    versionInfo.major > 15
+      ? (buildExecutionContext as any)({
+          schema,
+          document
+        })
+      : (buildExecutionContext as any)(schema, document);
+
+  const jsonSchema = queryToJSONSchema(context);
+  test("json schema creation", () => {
+    expect(jsonSchema).toMatchSnapshot();
+  });
+});

